{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root — one of the most central concepts in any logistics domain. It affects data modeling, external integrations, operational workflows, and the meaning of 'delivery' itself.",
    "bounded_context": "Shipment Management / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more destinations. The aggregate root that owns Recipients." },
      { "term": "Recipient", "definition": "A person or entity designated to receive part or all of a Shipment. Has a name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, signature requirements, safe-place authorization, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "In a multi-recipient shipment, the recipient designated as the default contact and billing reference. Must always exist." },
      { "term": "Shipment Completion", "definition": "Previously: delivery to the single recipient. Now requires redefinition — is a Shipment complete when ALL recipients have received their items, or when ANY has?" },
      { "term": "Split Shipment", "definition": "A shipment where goods are physically divided for delivery to multiple recipients. Distinct from a multi-drop route where the same package visits multiple stops." },
      { "term": "Delivery Attempt", "definition": "A single try to deliver goods to a specific Recipient. Must now be scoped per-Recipient rather than per-Shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no destination — it is physically and logically meaningless. This is a constraint of the real world, not a policy choice.",
      "testable_assertion": "Any attempt to create a Shipment with zero Recipients, or to remove the last Recipient from a Shipment, must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to attempt a physical delivery. Without them, a courier cannot locate or contact the recipient. This is an operational constraint, not a policy.",
      "testable_assertion": "Creating or adding a Recipient with a null/empty name, address, or phone number must be rejected at the domain level."
    },
    {
      "id": "BR-3",
      "rule": "Delivery preferences are per-Recipient, not per-Shipment. Two Recipients on the same Shipment may have conflicting preferences (e.g., one requires signature, one allows safe-place).",
      "invariant": true,
      "invariant_justification": "Preferences reflect the physical reality that each delivery destination has different access conditions and recipient availability. Flattening them to the Shipment level would corrupt the domain model.",
      "testable_assertion": "Recipient A can have delivery_preference='SIGNATURE_REQUIRED' while Recipient B on the same Shipment has delivery_preference='SAFE_PLACE', and both are honored independently."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient shipments must remain valid and require no migration of their data shape. The new model must treat a single-recipient shipment as a natural case of the multi-recipient model, not a legacy exception.",
      "invariant": false,
      "invariant_justification": "This is a migration policy — technically the business could choose to force-migrate, but backward compatibility is a strong business preference to avoid data corruption and downtime.",
      "testable_assertion": "All 2 million existing shipments must be queryable and behave identically after the model change, with no data migration required for basic operations."
    },
    {
      "id": "BR-5",
      "rule": "Shipment status must be derived from the aggregate state of all Recipient delivery statuses. The Shipment is not DELIVERED until ALL Recipients have received their deliveries.",
      "invariant": false,
      "invariant_justification": "This is a business policy decision — the business could alternatively define completion as 'all attempted' or use partial-delivery states. A VP could change this definition.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are DELIVERED and 1 is PENDING must have Shipment status != DELIVERED. It should be IN_PROGRESS or PARTIALLY_DELIVERED."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until partners have migrated to the new contract.",
      "invariant": false,
      "invariant_justification": "This is an integration policy. Partners could be force-migrated, but that is a business relationship decision, not a physical constraint.",
      "testable_assertion": "For multi-recipient shipments sent to legacy partner APIs, the system must either send one message per recipient or send only the primary recipient, per partner configuration."
    },
    {
      "id": "BR-7",
      "rule": "Delivery attempts, failures, and proof-of-delivery must be tracked per Recipient, not per Shipment.",
      "invariant": true,
      "invariant_justification": "A delivery attempt is a physical event at a specific address for a specific person. Tracking it at the Shipment level when there are multiple recipients would lose critical operational data and make dispute resolution impossible.",
      "testable_assertion": "Each Recipient on a Shipment has its own delivery attempt history, and querying delivery attempts for Recipient A does not return attempts for Recipient B."
    },
    {
      "id": "BR-8",
      "rule": "Pricing and billing must account for multiple recipients. A multi-recipient shipment may cost more than a single-recipient shipment due to additional stops, handling, or split logistics.",
      "invariant": false,
      "invariant_justification": "Pricing is a business policy. The business could choose to charge the same, charge per-recipient, or use distance-based pricing. This is a commercial decision.",
      "testable_assertion": "Adding a second Recipient to a Shipment triggers a pricing recalculation event."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The caller provides two or more Recipients with valid name, address, phone, and distinct delivery preferences",
      "then": "The Shipment is created successfully with all Recipients attached, each preserving their individual delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the model change",
      "when": "The Shipment is queried via the API",
      "then": "It returns successfully with the original Recipient data intact, represented as a list of one Recipient"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "The Shipment status is queried",
      "then": "The Shipment status is PARTIALLY_DELIVERED (or equivalent), not DELIVERED"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment",
      "when": "An external partner API integration sends shipment data to a partner that has NOT migrated to the new format",
      "then": "The partner receives data in the legacy single-recipient format (either per-recipient messages or primary-recipient only, per partner config)"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with two Recipients",
      "when": "A delivery attempt fails for Recipient A",
      "then": "The failed attempt is recorded against Recipient A only; Recipient B's delivery status and attempt history are unaffected"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with one Recipient",
      "when": "A caller attempts to remove that last Recipient",
      "then": "The operation is rejected with a domain error indicating a Shipment must have at least one Recipient"
    },
    {
      "id": "AC-7",
      "given": "A Shipment in DELIVERED status (all Recipients delivered)",
      "when": "A caller attempts to add a new Recipient",
      "then": "The operation is rejected — Recipients cannot be added to completed Shipments"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment is created",
      "when": "The pricing engine calculates the cost",
      "then": "The price reflects the additional recipients (multiple stops, handling, etc.) compared to a single-recipient baseline"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Two Recipients on the same Shipment have the exact same address",
      "expected_behavior": "This is valid — two different people at the same address (e.g., office colleagues). The system must not deduplicate by address. Each Recipient maintains independent delivery tracking."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already IN_TRANSIT",
      "expected_behavior": "This must be carefully evaluated. If the physical goods have already left the origin, adding a new recipient may require a split or re-routing. The domain should either reject late additions or trigger a re-routing workflow — never silently accept it."
    },
    {
      "scenario": "A multi-recipient Shipment is partially delivered and the sender requests a cancellation",
      "expected_behavior": "Only un-delivered Recipients can be cancelled. Already-delivered Recipients cannot be 'un-delivered.' The Shipment enters a mixed state: some delivered, some cancelled."
    },
    {
      "scenario": "External partner API receives a multi-recipient shipment but their schema only supports one recipient",
      "expected_behavior": "The integration layer must apply a transformation strategy per partner: either fan-out into N messages (one per recipient) or send only the primary recipient with a flag indicating multi-recipient. Silent data loss (dropping recipients) is never acceptable."
    },
    {
      "scenario": "A Shipment has 50 Recipients",
      "expected_behavior": "The system should enforce a sensible upper bound. A shipment with 50 recipients is likely a bulk/batch operation and should be modeled differently (e.g., as a Distribution or Campaign). The upper bound is a business policy decision but must exist to prevent abuse and operational chaos."
    },
    {
      "scenario": "Recipient delivery preferences conflict with Shipment-level constraints (e.g., hazmat shipment where a Recipient requests 'leave at door')",
      "expected_behavior": "Shipment-level constraints (regulatory, safety) override Recipient-level preferences. The system must validate preferences against Shipment constraints and reject or warn on conflicts."
    },
    {
      "scenario": "Reporting and analytics that count 'shipments delivered' — does a 3-recipient Shipment count as 1 delivery or 3?",
      "expected_behavior": "This is a critical business definition that must be decided explicitly. Recommendation: count as 1 Shipment delivered and 3 Recipient deliveries. Metrics that conflate these will produce misleading dashboards."
    },
    {
      "scenario": "Migration: existing shipment row has recipient data as direct columns (name, address, phone) rather than a related entity",
      "expected_behavior": "If the current schema stores recipient as columns on the Shipment table, migration to a Recipients table must preserve all 2M records without data loss. A backward-compatible view or adapter should make old queries work during transition."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments create new revenue opportunities (charge per additional recipient or per-stop) but also introduce pricing complexity. Incorrect pricing logic could cause revenue leakage. The migration itself has engineering cost (estimated weeks, not days) and must not cause downtime for the 2M existing shipments.",
    "operational": "This fundamentally changes dispatch, routing, and delivery tracking. Couriers need to know they have multiple stops for one shipment. Delivery status becomes more complex — customer service must understand partial delivery states. SLA tracking must shift from per-Shipment to per-Recipient.",
    "user": "Senders gain flexibility to ship to multiple recipients in one transaction. However, the UX for tracking becomes more complex — a sender checking 'where is my shipment?' now sees multiple delivery statuses. Recipients may be confused if they receive partial shipment notifications. The tracking page and notification system must be redesigned.",
    "risk": "HIGH. This changes a core aggregate root. Risks include: (1) data corruption during migration of 2M records, (2) breaking external partner integrations, (3) incorrect shipment status derivation causing operational errors, (4) pricing bugs causing revenue loss, (5) reporting metrics becoming meaningless if not redefined. The blast radius is the entire platform.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability but face a more complex creation and tracking experience" },
      { "group": "Recipients", "impact": "No direct change in delivery experience, but notification and tracking clarity may be affected if not handled well" },
      { "group": "Couriers/Drivers", "impact": "Must handle multi-stop shipments. Route optimization, delivery sequence, and proof-of-delivery workflows all change." },
      { "group": "Customer Service", "impact": "Must understand partial delivery states, per-recipient tracking, and more complex dispute resolution" },
      { "group": "External Partners (API consumers)", "impact": "Breaking change to integration contract. Must be managed via versioning or transformation layer. Partners on legacy format must not lose data." },
      { "group": "Finance/Billing", "impact": "Pricing model must evolve. Invoicing, refunds, and revenue recognition become per-recipient in some cases." },
      { "group": "Product/Analytics", "impact": "Core metrics (deliveries, success rates, SLA compliance) must be redefined at both Shipment and Recipient levels" }
    ]
  },

  "confidence": {
    "level": 62,
    "reasoning": "The spec clearly states the 'from' and 'to' state of the model (single → multi-recipient) and provides key context (2M existing records, external APIs). However, several critical business decisions are left undefined: (1) What does Shipment completion mean now? (2) How should partner APIs be handled — fan-out or primary-only? (3) Is there an upper bound on recipients? (4) How does pricing change? (5) What are the new Shipment statuses (PARTIALLY_DELIVERED?)? These ambiguities affect every downstream implementation decision.",
    "high_confidence_areas": [
      "The Recipient must become a separate entity with its own lifecycle",
      "Delivery tracking must move to per-Recipient granularity",
      "Existing data must be preserved without corruption",
      "External partner APIs require a compatibility layer"
    ],
    "low_confidence_areas": [
      "Definition of Shipment completion for multi-recipient shipments (ALL vs ANY)",
      "Partner API migration strategy (fan-out vs primary-only)",
      "Upper bound on number of Recipients per Shipment",
      "Pricing model for multi-recipient shipments",
      "Whether Recipients can be added/removed after Shipment creation or dispatch"
    ],
    "assumptions": [
      "The current data model stores Recipient as columns on the Shipment entity (not already a separate table)",
      "Delivery preferences are a new concept introduced alongside multi-recipient support",
      "There is no existing 'primary recipient' concept — it must be introduced",
      "External partners cannot be force-migrated simultaneously and need a transition period"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'Shipment completion' means for multi-recipient shipments. Is a Shipment DELIVERED when ALL recipients have received delivery, or when the LAST delivery attempt has been made (regardless of success)? This is the single most important business definition for the new model.",
      "affected_stakeholders": ["Senders/Shippers", "Customer Service", "Product/Analytics", "Finance/Billing"],
      "options": [
        "DELIVERED when ALL Recipients are successfully delivered",
        "DELIVERED when ALL Recipients have a terminal status (delivered, cancelled, or permanently failed)",
        "Introduce PARTIALLY_DELIVERED as an intermediate state"
      ],
      "recommendation": "Introduce PARTIALLY_DELIVERED and define DELIVERED as all Recipients having a terminal status. This matches physical reality and gives Customer Service clear states to work with."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not define the external partner API migration strategy. Multi-recipient shipments must be communicated to partners still on the single-recipient contract, but the strategy (fan-out into N messages vs. send primary recipient only) has very different data integrity and operational implications.",
      "affected_stakeholders": ["External Partners (API consumers)", "Product/Analytics"],
      "options": [
        "Fan-out: send one message per Recipient to legacy partners (risk: partner may create duplicate shipments)",
        "Primary-only: send only the primary Recipient (risk: partner loses visibility into other Recipients)",
        "Block: do not allow multi-recipient shipments for routes involving legacy partners until they migrate"
      ],
      "recommendation": "Default to primary-only with a multi-recipient flag, and allow per-partner configuration. Blocking is too restrictive; fan-out risks duplicate creation on partner side."
    },
    {
      "type": "missing_context",
      "description": "No upper bound specified for Recipients per Shipment. Without a limit, the model could be abused for bulk distribution, which is a fundamentally different logistics operation than multi-recipient delivery.",
      "affected_stakeholders": ["Couriers/Drivers", "Finance/Billing", "Product/Analytics"],
      "options": [
        "No limit (risk: operational chaos, unbounded routing complexity)",
        "Soft limit (e.g., 10) with override capability",
        "Hard limit based on vehicle/route constraints"
      ],
      "recommendation": "Set a hard limit of 10 Recipients per Shipment in v1. Bulk distribution (>10) should be a separate bounded context. The limit can be raised later based on operational data."
    },
    {
      "type": "ambiguity",
      "description": "The spec mentions 'delivery preferences' per Recipient but does not enumerate what preferences are available. Without a defined set, implementations will invent their own, leading to domain drift.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Customer Service"],
      "options": [
        "Define a fixed enum of delivery preferences now (e.g., SIGNATURE_REQUIRED, SAFE_PLACE, CONTACTLESS, TIME_WINDOW)",
        "Make preferences a flexible key-value structure",
        "Defer preference definition and only model the Recipient entity now"
      ],
      "recommendation": "Define a core enum of 4-5 delivery preferences for v1. A fully flexible key-value structure invites inconsistency. Additional preferences can be added as the domain matures."
    }
  ],

  "rejection_reasons": []
}

